import{_ as a,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const n="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",p=JSON.parse('{"title":"Request an Account","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/registering.md","filePath":"getting-started/registering.md"}'),i={name:"getting-started/registering.md"};function s(l,e,d,u,h,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="request-an-account" tabindex="-1">Request an Account <a class="header-anchor" href="#request-an-account" aria-label="Permalink to &quot;Request an Account&quot;">​</a></h1><p>New members usually join by <strong>requesting an account</strong>, which an admin then approves. This guide walks through the request and what happens next.</p><blockquote><p>Self‑registration can be turned <strong>off</strong> for a kingdom. If you don&#39;t see a way to register, ask your King or Alliance Leader to create an account for you instead.</p></blockquote><h2 id="sending-a-request" tabindex="-1">Sending a request <a class="header-anchor" href="#sending-a-request" aria-label="Permalink to &quot;Sending a request&quot;">​</a></h2><p><img src="'+n+'" alt="Registration request form"></p><ol><li>From the login screen, choose the option to <strong>request an account</strong> (registration).</li><li>Fill in the form with the details asked for (such as your name and the alliance you belong to).</li><li>Submit the form.</li></ol><p>Your request is now <strong>pending</strong> — it has been sent to your kingdom&#39;s admins for review. You cannot log in yet.</p><h2 id="what-pending-means" tabindex="-1">What &quot;pending&quot; means <a class="header-anchor" href="#what-pending-means" aria-label="Permalink to &quot;What &quot;pending&quot; means&quot;">​</a></h2><p>A pending request is simply waiting for a decision. Nobody has rejected you; an admin just hasn&#39;t acted on it yet. There are three things that can happen next:</p><ul><li><strong>Approved</strong> — your account is created and you can log in. You&#39;ll be given (or already have) a <a href="./../roles/overview.html">role</a> that sets what you can do.</li><li><strong>Needs more info</strong> — an admin needs something clarified before deciding. Provide what they ask for so they can continue.</li><li><strong>Rejected</strong> — the request was declined. If you think that&#39;s a mistake, contact your Alliance Leader or King.</li></ul><h2 id="after-you-re-approved" tabindex="-1">After you&#39;re approved <a class="header-anchor" href="#after-you-re-approved" aria-label="Permalink to &quot;After you&#39;re approved&quot;">​</a></h2><ol><li>Log in with the username and password for your new account (an admin may share a temporary password with you — you may be asked to change it on first sign‑in).</li><li>Take the quick tour: <a href="./navigating.html">Finding Your Way Around</a> and <a href="./dashboard-tour.html">Reading the Dashboard</a>.</li><li>If a page says you don&#39;t have access, that&#39;s expected — your role controls what&#39;s visible. See <a href="./access-denied.html">&quot;You don&#39;t have access&quot;</a>.</li></ol><h2 id="who-approves-requests" tabindex="-1">Who approves requests <a class="header-anchor" href="#who-approves-requests" aria-label="Permalink to &quot;Who approves requests&quot;">​</a></h2><p>Registration requests are handled by senior roles in your kingdom (Supreme Admin, King, or Alliance Leader). If your request has been pending for a while, a friendly nudge to one of them usually gets it moving.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./logging-in.html">Log In &amp; Out</a></li><li><a href="./your-profile.html">Edit Your Profile &amp; Password</a></li><li><a href="./../roles/overview.html">Roles Explained</a></li></ul>',16)])])}const m=a(i,[["render",s]]);export{p as __pageData,m as default};
